哈夫曼树 其实早就应该写完这个哈夫曼树，只不过最近有点没有心情学习。对于哈夫曼树的构造，我总结了以下几步： 取出元素构建子树 子树入队 构建新子树 将队列中的子树插入新子树，并入队 循环至最后一个子树 将队列中所有元素插入最后子树 程序 main.cpp #include &quot;hafuman.cpp&quot; #include &lt;cstdio&gt; #include &lt;cstdlib&gt; #include &lt;functional&gt; #include &lt;queue&gt; using namespace std; /* 运算符重载 */ struct mycmp { bool operator()(int a, int b) { //通过传入不同类型来定义不同类型优先级 return a &gt; b; //最小值优先 } }; int TestNum[] = {5, 4, 3, 2, 1}; int main(int argc, char const *argv[]) { /* 最小堆用于存放数据 */ priority_queue&lt;int, vector&lt;int&gt;, mycmp&gt; MyHeap; /* 队列于存放临时节点 */ queue&lt;HAFUNode_t&lt;int&gt;&gt; TempQueue; /* 哈夫曼树根节点 */ HAFUNode_t&lt;int&gt; HaFuTree = nullptr; /* 创建临时变量 */ int tright, tleft; /* 赋值 */ for (int i = 0; i &lt; 5; i++) { MyHeap.push(TestNum[i]); } printf(&quot;测试哈夫曼
&quot;); while (!MyHeap.empty()) { /* 优先队列非空 */ tleft = MyHeap.top(), MyHeap.pop(); /* 输出左值并释放 */ if (MyHeap.empty()) { /* 判断是否为空 */ break; } tright = MyHeap.top(), MyHeap.pop(); /* 输出右值并释放 */ /* 构造子树 */ HaFuTree = CreatSubTree(tleft, tright, tleft + tright); if (MyHeap.empty()) { /* 若为最后一个节点 */ break; } else { AutoJoin(HaFuTree, TempQueue); } /* 再加入元素 */ MyHeap.push(tleft + tright); } /* 将队列中所有的子树合并成一颗 */ while (!TempQueue.empty()) { FinalJoin(HaFuTree, TempQueue); } DrawTree(HaFuTree); return 0; } hafuman.cpp #include &quot;hafuman.h&quot; #include &lt;cmath&gt; #include &lt;cstdio&gt; #include &lt;cstdlib&gt; #include &lt;cstring&gt; #include &lt;iostream&gt; /** * @brief 构造一个子树 * @param[in] 类型T：左节点 右节点 * @param[out] * @return **/ template &lt;typename T&gt; HAFUNode_t&lt;T&gt; CreatSubTree(T Left, T Right, T Root) { /* set the root */ HAFUTree&lt;T&gt; *pH = (HAFUNode_t&lt;T&gt;)malloc(sizeof(struct HAFUTree&lt;T&gt;)); pH-&gt;data = Root; /* set the left child */ pH-&gt;left = (HAFUNode_t&lt;T&gt;)malloc(sizeof(struct HAFUTree&lt;T&gt;)); pH-&gt;left-&gt;data = Left; pH-&gt;left-&gt;left = nullptr; pH-&gt;left-&gt;right = nullptr; /* set the right child */ pH-&gt;right = (HAFUNode_t&lt;T&gt;)malloc(sizeof(struct HAFUTree&lt;T&gt;)); pH-&gt;right-&gt;data = Right; pH-&gt;right-&gt;left = nullptr; pH-&gt;right-&gt;right = nullptr; return pH; } /** * @brief 将一个根挂载在另一根的左侧 **/ template &lt;typename T&gt; static HAFUNode_t&lt;T&gt; LeftJoin(HAFUNode_t&lt;T&gt; LEFT, HAFUNode_t&lt;T&gt; ROOT) { free(ROOT-&gt;left); ROOT-&gt;left = LEFT; return ROOT; } /** * @brief 将一个根挂载在另一根的右侧 **/ template &lt;typename T&gt; static HAFUNode_t&lt;T&gt; RightJoin(HAFUNode_t&lt;T&gt; LEFT, HAFUNode_t&lt;T&gt; ROOT) { free(ROOT-&gt;right); ROOT-&gt;right = LEFT; return ROOT; } /** * @brief 将队中的子树插入新的子树，成功后保存至队列 **/ template &lt;typename T&gt; void AutoJoin(HAFUNode_t&lt;T&gt; NEW, std::queue&lt;HAFUNode_t&lt;T&gt;&gt; &amp;Q) { HAFUNode_t&lt;T&gt; temp = nullptr; if (Q.empty()) { Q.push(NEW); } else { /* Queue not empty then start insert */ // printf(&quot;NEW-&gt;data:%d Q.front()-&gt;left-&gt;data:%d
&quot;, NEW-&gt;data, // Q.front()-&gt;left-&gt;data); if (Q.front()-&gt;data == NEW-&gt;left-&gt;data) { /* left join */ temp = LeftJoin(Q.front(), NEW); Q.pop(); /* pop the old */ Q.push(temp); /* push the new root */ } else if (Q.front()-&gt;data == NEW-&gt;right-&gt;data) { temp = RightJoin(Q.front(), NEW); Q.pop(); Q.push(temp); } else { /* can&#39;t insert */ Q.push(NEW); } } } /** * @brief 最终插入，将队列中的元素插入到根中 **/ template &lt;typename T&gt; void FinalJoin(HAFUNode_t&lt;T&gt; ROOT, std::queue&lt;HAFUNode_t&lt;T&gt;&gt; &amp;Q) { // Q.front()-&gt;left-&gt;data); if (Q.front()-&gt;data == ROOT-&gt;left-&gt;data) { /* left join */ LeftJoin(Q.front(), ROOT); Q.pop(); /* pop the old */ } else if (Q.front()-&gt;data == ROOT-&gt;right-&gt;data) { RightJoin(Q.front(), ROOT); Q.pop(); } else { /* can&#39;t insert */ printf(&quot;insert error!
&quot;); } } /** * description 输出二叉树的高度 * @param[in] BinTree_t * @retval int **/ template &lt;typename T&gt; static int FindTreeHeight(HAFUNode_t&lt;T&gt; BT) { int rightlen, leftlen, maxlen; if (BT) { rightlen = FindTreeHeight(BT-&gt;right); leftlen = FindTreeHeight(BT-&gt;left); maxlen = leftlen &gt; rightlen ? leftlen : rightlen; return maxlen + 1; } else { return 0; } } /** * @brief 绘出树 **/ template &lt;typename T&gt; void DrawTree(HAFUNode_t&lt;T&gt; BT) { int height = FindTreeHeight(BT); int cnt = 0; /* 开始层序遍历二叉树并且绘制图形 */ std::queue&lt;HAFUNode_t&lt;T&gt;&gt; CurLevelqueue; /*记录当前层的元素 */ std::queue&lt;HAFUNode_t&lt;T&gt;&gt; NextLevelqueue; /*记录下一层的元素 */ std::queue&lt;HAFUNode_t&lt;T&gt;&gt; CurTempqueue; /*当前队列副本 */ std::queue&lt;HAFUNode_t&lt;T&gt;&gt; NextTempqueue; /*下一层队列副本 */ HAFUNode_t&lt;T&gt; temp, lasttemp = NULL; int width = 0; CurLevelqueue.push(BT); //将头节点入队s /*现在修改了入队函数,空指针也可以入队 所以在出队的时候就需要进行判断 */ for (int i = 0; i &lt; height; i++) { cnt = (int)pow(2, i); //当前行的个数21 width = pow(2, height - i + 1); //设置宽度为2^(height-i+1) CurTempqueue = CurLevelqueue; /* 临时记录 */ while (cnt--) { temp = CurLevelqueue.front(); if (temp != NULL) { printf(&quot;%*d%*c&quot;, width, temp-&gt;data, width, &#39; &#39;); NextLevelqueue.push(temp-&gt;left); NextLevelqueue.push(temp-&gt;right); //将下一层子节点入队 } else { printf(&quot;%*c%*c&quot;, width, &#39; &#39;, width, &#39; &#39;); NextLevelqueue.push(nullptr); NextLevelqueue.push(nullptr); //如果此层是空，那么再入两个空指针 } CurLevelqueue.pop(); //将上一层节点出队 } printf(&quot;
&quot;); NextTempqueue = NextLevelqueue; /* 记录下一层元素 */ /* 接下来打印层间符号 */ if (i != height - 1) { /* 若不是最后一行 */ /* 先记录下一行元素宽度间隔 */ int nextwidth = (int)pow(2, height - i); /* 并且以他下一层元素的个数打印&#39;-&#39; */ for (int k = 0; k &lt; (int)pow(2, i + 1); k++) { /* 每隔一位去打印width个&#39;-&#39; */ if ((k % 2) == 0) { /* 偶数位打印 空格+`-` */ if (NextTempqueue.front() != nullptr) { printf(&quot;%*c&quot;, nextwidth, &#39;-&#39;); for (uint8_t z = 0; z &lt; nextwidth; z++) { printf(&quot;-&quot;); } } else { printf(&quot;%*c&quot;, nextwidth, &#39; &#39;); for (uint8_t z = 0; z &lt; nextwidth; z++) { printf(&quot; &quot;); } } NextTempqueue.pop(); } else { /* 奇数位打印 空格+`-` */ if (NextTempqueue.front() != nullptr) { for (uint8_t z = 0; z &lt; nextwidth; z++) { printf(&quot;-&quot;); } printf(&quot;%*c&quot;, nextwidth, &#39; &#39;); } else { for (uint8_t z = 0; z &lt; nextwidth; z++) { printf(&quot; &quot;); } printf(&quot;%*c&quot;, nextwidth, &#39; &#39;); } NextTempqueue.pop(); } } printf(&quot;
&quot;); } printf(&quot;&quot;); swap(CurLevelqueue, NextLevelqueue); /* 交换队列 */ } } hafuman.h #ifndef _HAFUMAN_H #define _HAFUMAN_H #include &lt;queue&gt; /** * @brief the defination **/ template &lt;typename T&gt; struct HAFUTree; /** * @brief 别名 **/ template &lt;typename T&gt; using HAFUNode_t = struct HAFUTree&lt;T&gt; *; /** * @brief 结构体模板类 **/ template &lt;typename T&gt; struct HAFUTree { T data; HAFUNode_t&lt;T&gt; left; HAFUNode_t&lt;T&gt; right; }; #endif makefile CC = clang++ CFLAGS = -g # debug CLIBS = #-lpthread INCLUDE = $(wildcard ./*.h) # INCLUDE = a.h b.h ... can&#39;t be defined like &quot;INCLUDE = ./*.h&quot; SOURCES = $(wildcard ./*.cpp) TARGET = hafutree OBJECTS = $(patsubst %.cpp,%.o,$(SOURCES)) $(TARGET) : $(OBJECTS) $(CC) $(CFLAGS) $^ -o $@ $(CLIBS) $(OBJECTS) : %.o : %.cpp $(CC) -c $(CFLAGS) $&lt; -o $@ .PHONY : clean clean: rm -rf *.o $(TARGET) 编译运行 ➜ hafuman make &amp;&amp; ./hafutree clang++ -c -g hafuman.cpp -o hafuman.o clang++ -c -g main.cpp -o main.o clang++ -g hafuman.o main.o -o hafutree 测试哈夫曼 15 --------------------------------- 6 9 ----------------- ----------------- 3 3 4 5 --------- 1 2

堆 堆其实是也是一种二叉树，不过他的排序方式更加舒服，对于需要升序或者降序排列的数据非常有用。 代码 binheap.cpp #include &quot;binheap.h&quot; #include &lt;cstdint&gt; #include &lt;cstdio&gt; #include &lt;cstdlib&gt; #include &lt;cstring&gt; /** * @brief 优先队列-堆的数组实现 **/ PriorityQueue Initialize(int MaxElements) { PriorityQueue H = nullptr; if (MaxElements &lt; 0) { return nullptr; } /* 为队列结构体申请内存 */ H = (PriorityQueue)malloc(sizeof(struct HeapStruct)); /* 为队列数组申请内存 */ H-&gt;Elements = (ElementType *)malloc((MaxElements + 1) * sizeof(ElementType)); H-&gt;Capacity = MaxElements; H-&gt;Size = 0; H-&gt;Elements[0] = 0; /* scout element */ return H; } void Destroy(PriorityQueue H) {} void MakeEmpty(PriorityQueue H) {} /** * @brief 插入的元素都会塞满数组 **/ void Insert(ElementType X, PriorityQueue H) { int i; if (IsFull(H)) { return; } /*---&gt;1.指向数组的下一个元素 | | 2.判断当前元素是否小于其母节点 | | 3.小于:将母节点元素移动到此处 大于:X赋值到此处 ----v 4.指向母节点的位置 */ for (i = ++H-&gt;Size; H-&gt;Elements[i / 2] &gt; X; i /= 2) { H-&gt;Elements[i] = H-&gt;Elements[i / 2]; } H-&gt;Elements[i] = X; } /** * @brief 只需将较小的元素上移即可 **/ ElementType DeleteMin(PriorityQueue H) { int i, Child; ElementType MinElement, LastElement; if (IsEmpty(H)) { return H-&gt;Elements[0]; } /* 最小元素 */ MinElement = H-&gt;Elements[1]; /* 倒数第二个元素 */ LastElement = H-&gt;Elements[H-&gt;Size--]; for (i = 1; i * 2 &lt; H-&gt;Size; i = Child) { /* 子节点位置为当前节点的2倍 */ Child = i * 2; /* 选择左右子节点中小的那个 */ if (Child != H-&gt;Size &amp;&amp; (H-&gt;Elements[Child] &gt; H-&gt;Elements[Child + 1])) { Child++; } /* 没有到倒数第二个元素的右边 */ if (LastElement &gt; H-&gt;Elements[Child]) { /* 上浮 */ H-&gt;Elements[i] = H-&gt;Elements[Child]; } else { break; } } /* 交换最后一个元素 */ H-&gt;Elements[i] = LastElement; /* 返回删去的元素 */ return MinElement; } ElementType FindMin(PriorityQueue H) { if (IsEmpty(H)) { return 0; } else { return H-&gt;Elements[1]; } } int IsEmpty(PriorityQueue H) { if (H-&gt;Size == 0) { return true; } else { return false; } } int IsFull(PriorityQueue H) { if (H-&gt;Size == H-&gt;Capacity) { return true; } else { return false; } } void Traversal(PriorityQueue H) { if (IsEmpty(H)) { printf(&quot;Empty
&quot;); } else { for (int i = 1; i &lt;= H-&gt;Size; i++) { printf(&quot;%d &quot;, H-&gt;Elements[i]); } printf(&quot;
&quot;); } } binheap.h #ifndef _BinHeap_H #define _BinHeap_H #define ElementType int struct HeapStruct; typedef struct HeapStruct *PriorityQueue; PriorityQueue Initialize(int MaxElements); void Destroy(PriorityQueue H); void MakeEmpty(PriorityQueue H); void Insert(ElementType X, PriorityQueue H); ElementType DeleteMin(PriorityQueue H); ElementType FindMin(PriorityQueue H); int IsEmpty(PriorityQueue H); int IsFull(PriorityQueue H); void Traversal(PriorityQueue H); struct HeapStruct { int Capacity; int Size; ElementType *Elements; }; #endif main.cpp #include &quot;binheap.h&quot; #include &lt;cstdint&gt; #include &lt;cstdio&gt; #include &lt;cstdlib&gt; #include &lt;cstring&gt; void printUseage(void) { printf(&quot;\ 二叉堆操作：
\ (1):初始化
\ (2):插入元素
\ (3):删除最小值
\ (4):遍历元素
\ (q):退出
\ &quot;); } int main(int argc, char const *argv[]) { printUseage(); PriorityQueue heap; ElementType tempint; while (true) { switch (getchar()) { case &#39;1&#39;: printf(&quot;初始化大小为10的堆&quot;); heap = Initialize(10); printf(&quot;
&quot;); break; case &#39;2&#39;: printf(&quot;请输入插入元素:&quot;); scanf(&quot;%d&quot;, &amp;tempint); Insert(tempint, heap); printf(&quot;
&quot;); break; case &#39;3&#39;: printf(&quot;删除:%d&quot;, DeleteMin(heap)); printf(&quot;
&quot;); break; case &#39;4&#39;: printf(&quot;遍历堆:&quot;); Traversal(heap); printf(&quot;
&quot;); break; case &#39;q&#39;: exit(EXIT_SUCCESS); break; default: break; } } return 0; } Makefile CC = g++ CFLAGS = #-g CLIBS = #-lpthread INCLUDE = $(wildcard ./*.h) # INCLUDE = a.h b.h ... can&#39;t be defined like &quot;INCLUDE = ./*.h&quot; SOURCES = $(wildcard ./*.cpp) TARGET = BinHeap OBJECTS = $(patsubst %.cpp,%.o,$(SOURCES)) $(TARGET) : $(OBJECTS) $(CC) $(CFLAGS) $^ -o $@ $(CLIBS) rm -rf *.o $(OBJECTS) : %.o : %.cpp $(CC) -c $(CFLAGS) $&lt; -o $@ .PHONY : clean clean: rm -rf *.o $(TARGET) test 1 2 10 2 8 2 7 2 5 2 3 2 11 2 13 4 3 4 3 4 3 4 q 编译运行 ➜ heap make &amp;&amp; cat test | ./BinHeap g++ -c binheap.cpp -o binheap.o g++ -c main.cpp -o main.o g++ binheap.o main.o -o BinHeap rm -rf *.o 二叉堆操作： (1):初始化 (2):插入元素 (3):删除最小值 (4):遍历元素 (q):退出 初始化大小为10的堆 请输入插入元素: 请输入插入元素: 请输入插入元素: 请输入插入元素: 请输入插入元素: 请输入插入元素: 请输入插入元素: 遍历堆:3 5 8 10 7 11 13 删除:3 遍历堆:5 7 8 10 13 11 删除:5 遍历堆:7 10 8 11 13 删除:7 遍历堆:8 10 13 11

起因 最近用c++写的一个程序，我想用一个const char *p对一个char head[2]赋值，我使用strcpy赋值之后一直出现错误。我就写了个小程序去验证了一下。 程序 #include &lt;cstdint&gt; #include &lt;cstdio&gt; #include &lt;cstdlib&gt; #include &lt;cstring&gt; class CHARGET { private: char _head[2]; public: CHARGET(const char *p, int opt) { memset(_head, 0, 2); if (opt == 0) { _head[0] = *p++; _head[1] = *p++; } else if (opt == 1) { strcpy(_head, p); } else if (opt == 2) { strncpy(_head, p, 2); } else if (opt == 3) { strncpy(_head, p, 3); } else { return; } } void show(void) { printf(&quot;%s%.2d&quot;, _head, 2); } ~CHARGET() {} }; char test[2]; void CHARCPY(const char *p) { test[0] = *p++; test[1] = *p++; } int main(int argc, char const *argv[]) { /* 类中 直接指针幅值 */ printf(&quot;类中直接指针幅值
&quot;); CHARGET c1(&quot;HJ&quot;, 0); c1.show(); printf(&quot;

&quot;); /* strncpy 两字节 */ printf(&quot;strcpy
&quot;); CHARGET c2(&quot;HJ&quot;, 1); c2.show(); printf(&quot;

&quot;); /* strncpy 两字节 */ printf(&quot;strncpy 两字节
&quot;); CHARGET c3(&quot;HJ&quot;, 2); c3.show(); printf(&quot;

&quot;); /* strncpy 三字节 */ printf(&quot;strncpy 三字节
&quot;); CHARGET c4(&quot;HJ&quot;, 3); c4.show(); printf(&quot;

&quot;); /* 类外 直接指针幅值 */ printf(&quot;类外直接指针幅值
&quot;); CHARCPY(&quot;HJ&quot;); printf(&quot;%s%.2d&quot;, test, 2); printf(&quot;

&quot;); return 0; } 运行结果 类中直接指针幅值 HJ?T�+�02 strcpy HJ02 strncpy 两字节 HJHJ02 strncpy 三字节 HJ02 类外直接指针幅值 HJ02 分析 类中指针赋值 直接通过指针进行赋值： c _head[0] = *p++; _head[1] = *p++; 输出： sh HJ?T�+�02 HJ之后带有一串乱码，应该是由于c++在指针赋值时没有将第三位赋值为\0，导致打印输出时识别不到结束符一直输出。 strcpy赋值 直接用strcpy，看起来好像还行，但是到了下一步就发现问题了。 strncpy两字节 再新建一个类，然后对该类的_head进行strncpy两个字节。 输出： HJHJ02 应该是由于strncpy也没有在最后添加\0，并且新创建的变量的地址正好在之前变量的地址之前，最后出现了这个现象。 strncpy三字节 再新建一个类，然后对该类的_head进行strncpy三个字节。 输出: HJ02 说明这个时候是在字符串结尾添加了\0。 类外直接指针幅值 不使用类的方式，直接用函数的方式，进行赋值。 输出： HJ02 是没有问题的。

平衡二叉树 最后好久没写数据结构了，今天我把之前写的函数都写成C++的了。舒服的用一波C++中的queue和stack。 废话少说直接上代码（这次又调整了打印二叉树的程序 美滋滋） main.cpp #include &quot;bantree.h&quot; #include &lt;iostream&gt; using namespace std; void UseageHelp(void) { cout &lt;&lt; &quot;
 \ AVL树的操作
 \ (1).创建新的AVL树;
 \ (2).插入元素;
 \ (3).删除元素;
 \ (4).寻找最大元素;
 \ (5).寻找最小元素;
 \ (6).绘制二叉树;
 \ (h).帮助;
 \ (q).quit;
 \ &quot; &lt;&lt; endl; } int main(int argc, char const *argv[]) { ElementType i = 0; AvlTree pTree = NULL; AvlTree tmp = NULL; UseageHelp(); while (1) { switch (getchar()) { case &#39;1&#39;: pTree = MakeEmpty(pTree); cout &lt;&lt; &quot;创建成功 Tree:&quot; &lt;&lt; pTree &lt;&lt; endl; break; case &#39;2&#39;: cout &lt;&lt; &quot;请输入插入元素:&quot;; cin &gt;&gt; i; pTree = Insert(i, pTree); cout &lt;&lt; endl; break; case &#39;3&#39;: cout &lt;&lt; &quot;请输入删除元素:&quot;; cin &gt;&gt; i; Delete(i, pTree); cout &lt;&lt; endl; break; case &#39;4&#39;: tmp = FindMax(pTree); if (tmp != nullptr) { cout &lt;&lt; &quot;最大元素：&quot; &lt;&lt; tmp-&gt;Element &lt;&lt; endl; } cout &lt;&lt; endl; break; case &#39;5&#39;: tmp = FindMin(pTree); if (tmp != nullptr) { cout &lt;&lt; &quot;最小元素：&quot; &lt;&lt; tmp-&gt;Element &lt;&lt; endl; } cout &lt;&lt; endl; break; case &#39;6&#39;: DrawTree(pTree); cout &lt;&lt; endl; break; case &#39;h&#39;: UseageHelp(); break; case &#39;q&#39;: exit(0); break; default: break; } } return 0; } bantree.h #ifndef _BANTREE_H #define _BANTREE_H #define ElementType int struct AvlNode; typedef struct AvlNode *Position; typedef struct AvlNode *AvlTree; AvlTree MakeEmpty(AvlTree T); void DrawTree(AvlTree BT); Position Find(ElementType X, AvlTree T); Position FindMin(AvlTree T); Position FindMax(AvlTree T); AvlTree Insert(ElementType X, AvlTree T); AvlTree Delete(ElementType X, AvlTree T); ElementType Retrieve(Position P); Position SingleRotateWithLeft(Position K2); Position SingleRotateWithRight(Position K2); Position DoubleRotateWithLeft(Position K3); Position DoubleRotateWithRight(Position K3); struct AvlNode { ElementType Element; AvlTree Left; AvlTree Right; int Height; }; #endif bantree.cpp #include &quot;bantree.h&quot; #include &lt;cmath&gt; #include &lt;iostream&gt; #include &lt;queue&gt; #include &lt;stack&gt; #include &lt;string&gt; using namespace std; AvlTree MakeEmpty(AvlTree T) { if (T != nullptr) { MakeEmpty(T-&gt;Left); MakeEmpty(T-&gt;Right)